import{_ as o,o as t,c as a,ag as l}from"./chunks/framework.CpPsmr6h.js";const p=JSON.parse('{"title":"What Is TunnelBox?","description":"","frontmatter":{},"headers":[],"relativePath":"docs/overview.md","filePath":"docs/overview.md","lastUpdated":1771868171000}'),i={name:"docs/overview.md"};function n(r,e,s,u,c,d){return t(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="what-is-tunnelbox" tabindex="-1">What Is TunnelBox? <a class="header-anchor" href="#what-is-tunnelbox" aria-label="Permalink to &quot;What Is TunnelBox?&quot;">​</a></h1><p>TunnelBox is a hardware tunneling gateway that helps you expose local services to the public internet. It is designed to reduce networking complexity while keeping security and reliability in focus.</p><h2 id="why-tunnelbox" tabindex="-1">Why TunnelBox? <a class="header-anchor" href="#why-tunnelbox" aria-label="Permalink to &quot;Why TunnelBox?&quot;">​</a></h2><p>Many tunneling workflows require manual setup, CLI tooling, and network troubleshooting. TunnelBox is built to simplify that process:</p><ul><li>Minimal setup steps</li><li>Managed domain and TLS workflows</li><li>A dashboard-driven experience</li></ul><h2 id="who-is-tunnelbox-for" tabindex="-1">Who Is TunnelBox For? <a class="header-anchor" href="#who-is-tunnelbox-for" aria-label="Permalink to &quot;Who Is TunnelBox For?&quot;">​</a></h2><p>TunnelBox is useful for:</p><ul><li>Beginners learning how public endpoints work</li><li>Developers testing webhooks and API integrations</li><li>Teams running internal tools or demos</li><li>Startups exposing staging services quickly</li><li>Exposing your AI models to the public internet</li></ul><h2 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h2><ul><li><code>Device</code>: Your physical TunnelBox hardware.</li><li><code>Domain</code>: Public hostname mapped to your service.</li><li><code>Route</code>: Rule that forwards traffic from a domain/path to a local port.</li><li><code>Protocol</code>: The service type (HTTP, HTTP/2, TCP).</li></ul><h2 id="typical-setup-flow" tabindex="-1">Typical Setup Flow <a class="header-anchor" href="#typical-setup-flow" aria-label="Permalink to &quot;Typical Setup Flow&quot;">​</a></h2><ol><li>Connect and activate your TunnelBox device.</li><li>Register one or more domains.</li><li>Add routes from domain traffic to local services.</li><li>Verify reachability from outside your local network.</li></ol><h2 id="supported-protocols" tabindex="-1">Supported Protocols <a class="header-anchor" href="#supported-protocols" aria-label="Permalink to &quot;Supported Protocols&quot;">​</a></h2><ul><li><a href="/tunnelbox.net/docs/http">HTTP</a></li><li><a href="/tunnelbox.net/docs/http2">HTTP/2</a></li><li><a href="/tunnelbox.net/docs/tcp">TCP</a></li></ul><h2 id="what-to-read-next" tabindex="-1">What to Read Next <a class="header-anchor" href="#what-to-read-next" aria-label="Permalink to &quot;What to Read Next&quot;">​</a></h2><ol><li><a href="/tunnelbox.net/docs/tunnelbox">Registering a TunnelBox</a></li><li><a href="/tunnelbox.net/docs/domain">Registering Domains</a></li><li><a href="/tunnelbox.net/docs/routing">Routing Traffic</a></li><li><a href="/tunnelbox.net/docs/troubleshooting">Troubleshooting</a></li></ol>',16)])])}const x=o(i,[["render",n]]);export{p as __pageData,x as default};
